<?php
namespace App\Http\Controllers\Admin\Content;use App\Domain\Admin\Content\ContentAdminReadService;use App\Domain\Admin\Content\ContentAdminService;use App\Http\Controllers\Controller;use App\Http\Requests\Admin\Content\ItemRequest;use App\Models\Item;use InvalidArgumentException;
final class ItemController extends Controller{public function index(ContentAdminReadService $read){return view('admin.content.items.index',['items'=>$read->items()]);}public function create(ContentAdminReadService $read){return view('admin.content.items.form',['item'=>new Item(),'options'=>$read->itemOptions()]);}public function store(ItemRequest $request,ContentAdminService $service){try{$item=$service->saveItem($request->validated());return redirect()->route('admin.content.items.edit',$item)->with('status','Item creado.');}catch(InvalidArgumentException $e){return back()->withInput()->withErrors(['content'=>$e->getMessage()]);}}public function edit(Item $item,ContentAdminReadService $read){return view('admin.content.items.form',['item'=>$item,'itemSummary'=>$read->item($item),'options'=>$read->itemOptions($item)]);}public function update(ItemRequest $request,Item $item,ContentAdminService $service){try{$service->saveItem($request->validated(),$item);return back()->with('status','Item actualizado.');}catch(InvalidArgumentException $e){return back()->withInput()->withErrors(['content'=>$e->getMessage()]);}}public function destroy(Item $item,ContentAdminService $service){$service->deactivateItem($item);return back()->with('status','Item desactivado; no se eliminó físicamente.');}}
